import fs from "node:fs";
import path from "node:path";
import { describe, it, afterAll, vi, afterEach } from "vitest";
// __v2_realtimers_net: forks are shared (isolate:false) — never leak fake timers.
afterEach(() => { vi.useRealTimers(); });
import assert from "node:assert/strict";
import { makeTmpDir } from "../../tests/helpers/tmp.ts";
import { createManualClock } from "../harness/clock.js";

const tmpRoot = makeTmpDir("inbox-nudger-");

const { InboxStore } = await import("../../src/server/agent/inbox-store.ts");
const { InboxNudger } = await import("../../src/server/agent/inbox-nudger.ts");

afterAll(() => {
	try { fs.rmSync(tmpRoot, { recursive: true, force: true }); } catch { /* ok */ }
});

type StaffStatus = "idle" | "streaming" | "starting" | "terminated";

interface FakeSession {
	id: string;
	status: StaffStatus;
	rpcClient: {
		compact: ReturnType<typeof vi.fn>;
	};
}

function makeHarness(opts: {
	staffId?: string;
	contextPolicy?: "compact" | "preserve";
	staffState?: "active" | "paused" | "retired";
	sessionId?: string;
	sessionStatus?: StaffStatus;
	currentSessionId?: string | undefined;
}) {
	const stateDir = fs.mkdtempSync(path.join(tmpRoot, "h-"));
	const inboxStore = new InboxStore(stateDir);
	const staffId = opts.staffId ?? "staff-1";
	const sessionId = opts.sessionId ?? "session-1";
	const currentSessionId = ("currentSessionId" in opts) ? opts.currentSessionId : sessionId;
	const staff: any = {
		id: staffId,
		state: opts.staffState ?? "active",
		currentSessionId,
		contextPolicy: opts.contextPolicy ?? "compact",
	};
	const staffManager = {
		listStaff: () => [staff],
		getStaff: (id: string) => (id === staffId ? staff : undefined),
		updateStaff: vi.fn((id: string, patch: Record<string, unknown>) => { if (id === staffId) Object.assign(staff, patch); return staff; }),
	};

	const session: FakeSession = {
		id: sessionId,
		status: opts.sessionStatus ?? "idle",
		rpcClient: { compact: vi.fn(async (_t?: number) => undefined) },
	};
	const enqueuePrompt = vi.fn(async (_id: string, _msg: string, _opts?: any) => {});
	const sessionManager = {
		getSession: (id: string) => (id === sessionId ? session : undefined),
		enqueuePrompt,
	};

	const clock = createManualClock();
	const nudger = new InboxNudger({
		sessionManager: sessionManager as any,
		staffManager: staffManager as any,
		inboxStore,
		clock,
	});

	return { nudger, staff, session, staffManager, sessionManager, inboxStore, enqueuePrompt, clock };
}

function enqueueDirect(inboxStore: InstanceType<typeof InboxStore>, staffId: string, id = "e1") {
	inboxStore.put({
		id,
		staffId,
		source: { type: "trigger", triggerId: "t1" },
		title: "t",
		prompt: "do thing",
		state: "pending",
		createdAt: Date.now(),
	});
}

describe("InboxNudger — periodic tick", () => {
	it("wakes an idle staff with pending entries on the next tick", async () => {
		const h = makeHarness({});
		enqueueDirect(h.inboxStore, h.staff.id);
		h.nudger.start();

		h.clock.advance(15_000);
		// Yield so microtasks (poke / applyPolicyThenNudge) settle.
		await new Promise((r) => setImmediate(r));
		await new Promise((r) => setImmediate(r));

		assert.equal(h.enqueuePrompt.mock.calls.length, 1);
		const call = h.enqueuePrompt.mock.calls[0];
		assert.equal(call[0], h.session.id);
		assert.match(call[1], /\[INBOX\] You have 1 pending item\./);
		assert.deepEqual(call[2], { isSteered: true });

		h.nudger.stop();
	});

	it("uses pluralised wording for multiple pending entries", async () => {
		const h = makeHarness({});
		enqueueDirect(h.inboxStore, h.staff.id, "e1");
		enqueueDirect(h.inboxStore, h.staff.id, "e2");
		enqueueDirect(h.inboxStore, h.staff.id, "e3");
		h.nudger.start();

		h.clock.advance(15_000);
		await new Promise((r) => setImmediate(r));
		await new Promise((r) => setImmediate(r));

		assert.equal(h.enqueuePrompt.mock.calls.length, 1);
		assert.match(h.enqueuePrompt.mock.calls[0][1], /3 pending items/);
		h.nudger.stop();
	});

	it("does NOT wake a streaming staff", async () => {
		const h = makeHarness({ sessionStatus: "streaming" });
		enqueueDirect(h.inboxStore, h.staff.id);
		h.nudger.start();

		h.clock.advance(15_000);
		await new Promise((r) => setImmediate(r));
		assert.equal(h.enqueuePrompt.mock.calls.length, 0);
		h.nudger.stop();
	});

	it("does NOT wake a starting staff", async () => {
		const h = makeHarness({ sessionStatus: "starting" });
		enqueueDirect(h.inboxStore, h.staff.id);
		h.nudger.start();

		h.clock.advance(15_000);
		await new Promise((r) => setImmediate(r));
		assert.equal(h.enqueuePrompt.mock.calls.length, 0);
		h.nudger.stop();
	});

	it("does NOT wake when inbox is empty", async () => {
		const h = makeHarness({});
		h.nudger.start();

		h.clock.advance(15_000);
		await new Promise((r) => setImmediate(r));
		assert.equal(h.enqueuePrompt.mock.calls.length, 0);
		h.nudger.stop();
	});

	it("skips paused / retired staff", async () => {
		const h = makeHarness({ staffState: "paused" });
		enqueueDirect(h.inboxStore, h.staff.id);
		h.nudger.start();

		h.clock.advance(15_000);
		await new Promise((r) => setImmediate(r));
		assert.equal(h.enqueuePrompt.mock.calls.length, 0);
		h.nudger.stop();
	});

	it("skips staff with no currentSessionId", async () => {
		const h = makeHarness({ currentSessionId: undefined });
		enqueueDirect(h.inboxStore, h.staff.id);
		h.nudger.start();

		h.clock.advance(15_000);
		await new Promise((r) => setImmediate(r));
		assert.equal(h.enqueuePrompt.mock.calls.length, 0);
		h.nudger.stop();
	});

	it("guards re-nudge via nudgePending until onAgentStart clears it", async () => {
		const h = makeHarness({});
		enqueueDirect(h.inboxStore, h.staff.id, "e1");
		h.nudger.start();

		h.clock.advance(15_000);
		await new Promise((r) => setImmediate(r));
		await new Promise((r) => setImmediate(r));
		assert.equal(h.enqueuePrompt.mock.calls.length, 1, "first tick wakes once");

		// Add another pending entry; without clearing the guard, no second wake.
		enqueueDirect(h.inboxStore, h.staff.id, "e2");
		h.clock.advance(15_000);
		await new Promise((r) => setImmediate(r));
		assert.equal(h.enqueuePrompt.mock.calls.length, 1, "guard suppresses the second wake");

		// Simulate the agent starting its turn — clears the guard.
		h.nudger.onAgentStart(h.session.id);
		h.clock.advance(15_000);
		await new Promise((r) => setImmediate(r));
		await new Promise((r) => setImmediate(r));
		assert.equal(h.enqueuePrompt.mock.calls.length, 2, "post-agent_start tick wakes again");

		h.nudger.stop();
	});
});

describe("InboxNudger — contextPolicy", () => {
	it("\"compact\" runs session.rpcClient.compact(120_000) BEFORE enqueuePrompt", async () => {
		const h = makeHarness({ contextPolicy: "compact" });
		enqueueDirect(h.inboxStore, h.staff.id);
		h.nudger.start();

		// Capture call order across compact and enqueuePrompt.
		const order: string[] = [];
		const compactImpl = async (_t?: number) => { order.push("compact"); };
		h.session.rpcClient.compact = vi.fn(compactImpl);
		h.enqueuePrompt.mockImplementation(async () => { order.push("enqueue"); });

		h.clock.advance(15_000);
		await new Promise((r) => setImmediate(r));
		await new Promise((r) => setImmediate(r));
		await new Promise((r) => setImmediate(r));

		assert.equal(h.session.rpcClient.compact.mock.calls.length, 1);
		assert.equal(h.session.rpcClient.compact.mock.calls[0][0], 120_000);
		assert.deepEqual(order, ["compact", "enqueue"]);
		h.nudger.stop();
	});

	it("\"preserve\" skips compact and goes straight to enqueuePrompt", async () => {
		const h = makeHarness({ contextPolicy: "preserve" });
		enqueueDirect(h.inboxStore, h.staff.id);
		h.nudger.start();

		h.clock.advance(15_000);
		await new Promise((r) => setImmediate(r));
		await new Promise((r) => setImmediate(r));

		assert.equal(h.session.rpcClient.compact.mock.calls.length, 0);
		assert.equal(h.enqueuePrompt.mock.calls.length, 1);
		h.nudger.stop();
	});

	it("tolerates an rpcClient without a compact() method (test double)", async () => {
		const h = makeHarness({ contextPolicy: "compact" });
		// Drop compact entirely.
		(h.session.rpcClient as any).compact = undefined;
		enqueueDirect(h.inboxStore, h.staff.id);
		h.nudger.start();

		h.clock.advance(15_000);
		await new Promise((r) => setImmediate(r));
		await new Promise((r) => setImmediate(r));

		// Still nudges — the missing compact is treated as a no-op.
		assert.equal(h.enqueuePrompt.mock.calls.length, 1);
		h.nudger.stop();
	});
});

describe("InboxNudger.poke fast-path", () => {
	it("delivers a wake within microtask scheduling (no 15 s wait)", async () => {
		// We do NOT enable mock timers here — we want the real microtask loop.
		const h = makeHarness({ contextPolicy: "preserve" });
		enqueueDirect(h.inboxStore, h.staff.id);
		// Note: nudger.start() is NOT called — poke should still fire tickOne.

		h.nudger.poke(h.staff.id);
		// Microtask scheduled inside poke. Flush microtasks; then any pending
		// promise from enqueuePrompt.
		await Promise.resolve();
		await Promise.resolve();
		await new Promise((r) => setImmediate(r));

		assert.equal(h.enqueuePrompt.mock.calls.length, 1);
	});

	it("poke against a streaming staff is a no-op (gated by tickOne)", async () => {
		const h = makeHarness({ sessionStatus: "streaming" });
		enqueueDirect(h.inboxStore, h.staff.id);
		h.nudger.poke(h.staff.id);
		await Promise.resolve();
		await new Promise((r) => setImmediate(r));
		assert.equal(h.enqueuePrompt.mock.calls.length, 0);
	});
});

describe("InboxNudger.start/stop", () => {
	it("stop clears the interval (no further ticks)", async () => {
		const h = makeHarness({});
		enqueueDirect(h.inboxStore, h.staff.id);
		h.nudger.start();
		h.nudger.stop();

		h.clock.advance(15_000 * 5);
		await new Promise((r) => setImmediate(r));
		assert.equal(h.enqueuePrompt.mock.calls.length, 0);
	});

	it("start is idempotent (calling twice does not double-tick)", async () => {
		const h = makeHarness({});
		enqueueDirect(h.inboxStore, h.staff.id);
		h.nudger.start();
		h.nudger.start();

		h.clock.advance(15_000);
		await new Promise((r) => setImmediate(r));
		await new Promise((r) => setImmediate(r));
		assert.equal(h.enqueuePrompt.mock.calls.length, 1);

		h.nudger.stop();
	});
});
